const crypto = require('crypto');
try {
  const cookieStr = $input.first().json.headers.cookie || '';
  const token = cookieStr.split(';').find(c => c.trim().startsWith('sdlc_token='))?.split('=')[1];
  if (!token) return [{ json: { authenticated: false, error: 'Unauthorized' } }];

  const parts = token.split('.');
  if (parts.length !== 3) return [{ json: { authenticated: false, error: 'Invalid token' } }];

  const [header, payload, signature] = parts;
  const expectedSig = crypto.createHmac('sha256', $env.JWT_SECRET).update(`${header}.${payload}`).digest('base64url');
  if (signature !== expectedSig) return [{ json: { authenticated: false, error: 'Invalid signature' } }];

  const data = JSON.parse(Buffer.from(payload, 'base64url').toString());
  if (data.exp < Date.now() / 1000) return [{ json: { authenticated: false, error: 'Token expired' } }];

  return [{ json: { authenticated: true, user: data.username, body: $input.first().json.body } }];
} catch (err) {
  return [{ json: { authenticated: false, error: err.message } }];
}

const tree = $('Get Tree').first().json.tree;
const payload = $('Valideer Auth').first().json.body;
const templateFile = $input.first().json.content;

const type = payload.type || 'ISS';
const project = payload.project;

let count = 0;
tree.forEach(item => {
    if (item.path.startsWith(`projects/${project}/backlog/`)) {
        const fileMatch = item.path.match(/projects\/[^\/]+\/backlog\/[^\/]+\/([A-Z]+)-(\d+)_/);
        if (fileMatch && fileMatch[1] === type) {
            const num = parseInt(fileMatch[2], 10);
            if (num > count) count = num;
        }
    }
});

const nextId = `${type}-${String(count + 1).padStart(3, '0')}`;
const rawTemplate = Buffer.from(templateFile, 'base64').toString('utf8');
const now = new Date().toISOString().split('T')[0];

const typeFolderMap = { 'BUG': 'bugs', 'ISS': 'issues', 'FE': 'features', 'US': 'stories', 'EP': 'epics' };
const folder = typeFolderMap[type] || 'issues';

const titleStr = payload.title || 'Untitled';
const slug = titleStr.toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/^-|-$/g, '');
const filePath = `projects/${project}/backlog/${folder}/${nextId}_${slug}.md`;

let updatedMarkdown = rawTemplate;
updatedMarkdown = updatedMarkdown.replace(/^id:\s*.*$/m, `id: ${nextId}`);
updatedMarkdown = updatedMarkdown.replace(/^type:\s*.*$/m, `type: ${type.toLowerCase()}`);
updatedMarkdown = updatedMarkdown.replace(/^project:\s*.*$/m, `project: ${project}`);
updatedMarkdown = updatedMarkdown.replace(/^title:\s*.*$/m, `title: "${titleStr.replace(/"/g, '\\"')}"`);
updatedMarkdown = updatedMarkdown.replace(/^priority:\s*.*$/m, `priority: ${payload.priority}`);
updatedMarkdown = updatedMarkdown.replace(/^created:\s*.*$/m, `created: ${now}`);
updatedMarkdown = updatedMarkdown.replace(/^updated:\s*.*$/m, `updated: ${now}`);

if (type === 'BUG' && payload.severity) {
    updatedMarkdown = updatedMarkdown.replace(/^severity:\s*.*$/m, `severity: ${payload.severity}`);
}
if (['FE', 'US'].includes(type) && payload.parent_epic) {
    updatedMarkdown = updatedMarkdown.replace(/^epic:\s*.*$/m, `epic: ${payload.parent_epic}`);
}

const parts = updatedMarkdown.split('---');
if (parts.length >= 3) {
    let frontmatter = parts[1];
    let body = parts.slice(2).join('---');
    const desc = payload.description || '';
    if (body.includes('## Beschrijving')) {
        body = body.replace('## Beschrijving', `## Beschrijving\n\n${desc}\n`);
    } else {
        body = `\n${desc}\n` + body;
    }
    updatedMarkdown = `---${frontmatter}---${body}`;
}

const contentBase64 = Buffer.from(updatedMarkdown).toString('base64');

return [{
    json: {
        file_path: filePath,
        content_base64: contentBase64,
        item_id: nextId,
        title: titleStr,
        message: `chore: create ${nextId} van dashboard`
    }
}];
